import{_ as o,o as n,c as s,a0 as a}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"資料分析","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/11.md","filePath":"clf-c02/11.md","lastUpdated":1783610848000}'),r={name:"clf-c02/11.md"};function e(i,t,g,l,d,h){return n(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="資料分析" tabindex="-1">資料分析 <a class="header-anchor" href="#資料分析" aria-label="Permalink to &quot;資料分析&quot;">​</a></h1><p>Kinesis、Lake Formation、Glue、Athena、EMR、QuickSight。AI/ML 要有效，前提是有乾淨、整理好的資料——資料分析是 AI/ML 的上游基礎。這章把原始資料從「收集 → 儲存 → 處理 → 分析 → 視覺化」五個階段，逐一對應到 AWS 服務。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>資料分析（Data Analysis）</strong> 🔍 任一篇「什麼是資料分析 data analytics」入門即可</p></li><li><p><strong>資料湖 vs 資料倉儲（Data Lake / Data Warehouse）</strong> 🔍 任一篇「data lake data warehouse 差異」入門即可</p></li><li><p><strong>ETL（Extract → Transform → Load）</strong></p><ul><li><a href="https://aws.amazon.com/tw/what-is/etl/" target="_blank" rel="noreferrer">什麼是 ETL？（AWS，繁中）</a></li></ul></li></ul><h2 id="為什麼資料要走「五個階段」" tabindex="-1">為什麼資料要走「五個階段」 <a class="header-anchor" href="#為什麼資料要走「五個階段」" aria-label="Permalink to &quot;為什麼資料要走「五個階段」&quot;">​</a></h2><p>原始資料剛產生時，通常是<strong>又亂又雜、不能直接拿來用</strong>的：來自感測器的一串串數字、網站的點擊記錄、上傳的 PDF、四散各處的 log。要把這堆東西變成「老闆看得懂的報表」或「能餵給 AI 的乾淨資料」，中間得走一條路：</p><p><strong>先把資料收進來（收集）→ 找地方存起來（儲存）→ 清洗整理成好用的格式（處理／轉換）→ 對它提問、跑分析（分析）→ 把結果畫成圖表（視覺化）。</strong></p><p>AWS 針對這條路上的<strong>每一站</strong>，都準備了對應的服務。這章的重點不是背服務名，而是搞懂「<strong>每個服務站在這條路的哪一站、解決哪一段的麻煩</strong>」——站位清楚了，考題問「這個情境該用哪個」就會自己浮出來。</p><h2 id="典型資料管線-五階段" tabindex="-1">典型資料管線（五階段） <a class="header-anchor" href="#典型資料管線-五階段" aria-label="Permalink to &quot;典型資料管線（五階段）&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>收集 ──────→ 儲存 ───────→ 處理/轉換 ──→ 分析 ──────────→ 視覺化</span></span>
<span class="line"><span>Kinesis      S3 +           Glue          Athena /        QuickSight</span></span>
<span class="line"><span>(即時串流)   Lake Formation  (ETL)         Redshift / EMR  (儀表板)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>服務</th><th>管線角色</th><th>一句話</th></tr></thead><tbody><tr><td><strong>Kinesis</strong></td><td>收集</td><td><strong>即時串流</strong>資料的收集與處理（點擊流、IoT 感測器）</td></tr><tr><td><strong>S3 + Lake Formation</strong></td><td>儲存</td><td>資料存在 <strong>S3</strong>；Lake Formation 幫你<strong>快速建置並治理</strong>這個資料湖</td></tr><tr><td><strong>Glue</strong></td><td>處理 / 轉換</td><td>無伺服器 <strong>ETL</strong>（萃取、轉換、載入）＋ 資料目錄</td></tr><tr><td><strong>Athena</strong></td><td>分析</td><td>用 <strong>SQL 直接查詢 S3</strong> 上的資料，完全無伺服器</td></tr><tr><td><strong>EMR</strong></td><td>分析</td><td>託管大數據框架（Hadoop / Spark），處理超大規模資料</td></tr><tr><td><strong>Redshift</strong></td><td>分析</td><td><strong>資料倉儲</strong>，跑複雜分析 / BI</td></tr><tr><td><strong>QuickSight</strong></td><td>視覺化</td><td>BI <strong>儀表板與圖表</strong>，把分析結果視覺化</td></tr></tbody></table><hr><h2 id="逐一認識每個服務" tabindex="-1">逐一認識每個服務 <a class="header-anchor" href="#逐一認識每個服務" aria-label="Permalink to &quot;逐一認識每個服務&quot;">​</a></h2><h3 id="收集-amazon-kinesis" tabindex="-1">收集｜Amazon Kinesis <a class="header-anchor" href="#收集-amazon-kinesis" aria-label="Permalink to &quot;收集｜Amazon Kinesis&quot;">​</a></h3><p><strong>它是什麼</strong>：專門「接住源源不絕、即時湧入的資料」的服務。想像一個新聞網站每秒有上萬人點擊、或工廠上千個感測器每秒回報溫度——這些資料<strong>一產生就要馬上接住、不能漏</strong>，這就是 Kinesis 的舞台。</p><p><strong>為什麼需要它</strong>：傳統做法是「累積一批、之後再一次處理」（批次）；但很多場景等不了——詐騙偵測、即時儀表板、IoT 監控都要「資料一進來就處理」。Kinesis 就是這條「即時串流」的水管。</p><p><strong>補充</strong>：Kinesis 其實是一個家族，CLF 只要記兩個代表——<strong>Data Streams</strong>（即時串流、可自訂消費端）與 <strong>Data Firehose</strong>（全託管，自動把串流資料「倒進」S3 / Redshift 等目的地）。</p><blockquote><p>📌 看到「即時串流、點擊流、IoT 感測器、即時處理」→ <strong>Kinesis</strong>。</p></blockquote><h3 id="儲存-amazon-s3-aws-lake-formation" tabindex="-1">儲存｜Amazon S3 + AWS Lake Formation <a class="header-anchor" href="#儲存-amazon-s3-aws-lake-formation" aria-label="Permalink to &quot;儲存｜Amazon S3 + AWS Lake Formation&quot;">​</a></h3><p><strong>先分清楚兩者的關係</strong>：資料<strong>實際上是存在 S3</strong> 裡的（S3 就是那個能裝海量、任何格式資料的「大倉庫」，也就是<strong>資料湖</strong>的底層）。<strong>Lake Formation 不是另一個儲存體</strong>，而是蓋在 S3 之上的「<strong>建置＋管理</strong>」工具。</p><p><strong>Lake Formation 幫你做什麼</strong>：手動從零打造一個安全的資料湖很繁瑣——要設定 S3、爬梳資料、編目錄、再一項項設權限。Lake Formation 把這些整合起來，讓你<strong>快速把資料湖建好</strong>，並且能做到<strong>細緻的權限控管</strong>（誰能看哪個資料表、甚至哪些欄位）。</p><blockquote><p>📌 「集中存放各種原始資料、建資料湖」→ 資料在 <strong>S3</strong>，用 <strong>Lake Formation</strong> 快速建置與控管權限。</p></blockquote><h3 id="處理-轉換-aws-glue" tabindex="-1">處理／轉換｜AWS Glue <a class="header-anchor" href="#處理-轉換-aws-glue" aria-label="Permalink to &quot;處理／轉換｜AWS Glue&quot;">​</a></h3><p><strong>它是什麼</strong>：無伺服器的 <strong>ETL</strong> 服務——把原始資料<strong>萃取（Extract）出來、轉換（Transform）成乾淨格式、載入（Load）到目的地</strong>。原始資料常常髒亂（缺欄位、格式不一、混著垃圾），Glue 就是那個「幫你把資料洗乾淨、整理好」的工人，而且你不用管任何伺服器。</p><p><strong>一個容易被忽略、卻很關鍵的角色——Glue Data Catalog</strong>：Glue 有個「爬蟲（Crawler）」會自動掃描 S3 裡的資料，推導出它「長什麼樣、有哪些欄位」，把這份「資料的目錄」記進 <strong>Glue Data Catalog</strong>。有了這份目錄，後面的 <strong>Athena、Redshift 才知道 S3 那堆檔案該怎麼查</strong>。所以 Glue 不只是「洗資料」，還是「幫資料湖編目錄」的人。</p><blockquote><p>📌 「ETL / 整理轉換資料」「自動爬取 S3 結構、建立統一目錄」→ <strong>Glue</strong>。</p></blockquote><h3 id="分析-三種不同的「分析」-athena-emr-redshift" tabindex="-1">分析｜三種不同的「分析」：Athena / EMR / Redshift <a class="header-anchor" href="#分析-三種不同的「分析」-athena-emr-redshift" aria-label="Permalink to &quot;分析｜三種不同的「分析」：Athena / EMR / Redshift&quot;">​</a></h3><p>管線的「分析」階段有三個服務，初學者最容易混。它們都在做分析，但<strong>適合的場景完全不同</strong>：</p><p><strong>Amazon Athena——最輕巧的一個</strong>。它讓你<strong>直接用 SQL 查詢 S3 上的檔案</strong>，不必先架資料庫、不必把資料搬進任何地方、也沒有任何伺服器要管。最典型的用法是「快速查一下 log」（例如 ALB 的存取紀錄）。計費方式是<strong>按查詢掃描的資料量</strong>，所以資料量大時常把檔案轉成壓縮的欄狀格式（如 Parquet）來省錢。</p><blockquote><p>📌 「不想建資料庫、無伺服器、直接用 SQL 查 S3」→ <strong>Athena</strong>。</p></blockquote><p><strong>Amazon EMR——最重裝的一個</strong>。當資料大到、或處理邏輯複雜到 SQL 搞不定時（例如要跑機器學習前處理、超大規模資料清洗），就需要 <strong>Hadoop / Spark</strong> 這類大數據框架。EMR 是「幫你把這些框架的叢集託管起來」的服務——你仍要寫程式、管比較多東西，換來的是處理超大規模、超複雜運算的能力。</p><blockquote><p>📌 「Hadoop / Spark、超大規模資料清洗」→ <strong>EMR</strong>。</p></blockquote><p><strong>Amazon Redshift——資料倉儲</strong>。當你要對<strong>已經整理好的結構化資料</strong>，反覆跑<strong>複雜的商業分析與報表（BI）</strong>——例如「過去三年各地區銷售趨勢」——就用 Redshift。它是專為這種大規模分析查詢（OLAP）打造的倉儲，資料要先載入進來，換來的是又快又強的分析能力。</p><blockquote><p>📌 「資料倉儲、BI、對海量歷史資料跑複雜分析（OLAP）」→ <strong>Redshift</strong>。</p></blockquote><blockquote><p>💡 <strong>一句話分辨</strong>：臨時查一下 S3 → <strong>Athena</strong>；要跑 Hadoop/Spark 的重運算 → <strong>EMR</strong>；要對結構化資料做正式 BI 分析 → <strong>Redshift</strong>。</p></blockquote><h3 id="視覺化-amazon-quicksight" tabindex="-1">視覺化｜Amazon QuickSight <a class="header-anchor" href="#視覺化-amazon-quicksight" aria-label="Permalink to &quot;視覺化｜Amazon QuickSight&quot;">​</a></h3><p><strong>它是什麼</strong>：AWS 的 <strong>BI（商業智慧）視覺化工具</strong>。前面辛苦分析出來的結果，如果只是一堆數字，老闆和團隊看不懂——QuickSight 把它們變成<strong>互動式的圖表與儀表板</strong>。它是無伺服器的，可以接上 Athena、Redshift、RDS、S3 等來源，直接把資料畫成圖。</p><blockquote><p>📌 「做 BI 儀表板 / 把分析結果視覺化」→ <strong>QuickSight</strong>。</p></blockquote><hr><h2 id="高頻辨別" tabindex="-1">高頻辨別 <a class="header-anchor" href="#高頻辨別" aria-label="Permalink to &quot;高頻辨別&quot;">​</a></h2><ul><li>「即時串流、IoT、點擊流」→ <strong>Kinesis</strong></li><li>「集中存原始資料、建資料湖」→ 資料在 <strong>S3</strong>，用 <strong>Lake Formation</strong> 建置治理</li><li>「ETL / 整理轉換 / 自動建資料目錄」→ <strong>Glue</strong></li><li>「不建資料庫、無伺服器、用 SQL 查 S3」→ <strong>Athena</strong></li><li>「Hadoop / Spark 超大規模處理」→ <strong>EMR</strong></li><li>「資料倉儲、複雜 BI 分析（OLAP）」→ <strong>Redshift</strong></li><li>「BI 儀表板 / 視覺化」→ <strong>QuickSight</strong></li></ul><hr><h2 id="以電商場景為例" tabindex="-1">以電商場景為例 <a class="header-anchor" href="#以電商場景為例" aria-label="Permalink to &quot;以電商場景為例&quot;">​</a></h2><p>把這些服務串起來，看它們如何在一個真實業務裡各司其職：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用者上傳發票 (PDF)</span></span>
<span class="line"><span>   ↓ Textract 萃取文字與金額         ← M8 現成 AI 服務</span></span>
<span class="line"><span>   ↓ Comprehend 分析內容              ← M8 現成 AI 服務</span></span>
<span class="line"><span>   ↓ 資料進 S3</span></span>
<span class="line"><span>     → Glue 整理轉換（ETL）</span></span>
<span class="line"><span>     → Athena / QuickSight 分析與儀表板</span></span>
<span class="line"><span>平行：Personalize 依購買記錄做個人化推薦  ← M8 現成 AI 服務</span></span>
<span class="line"><span>客服：Lex 聊天機器人接一般問題，複雜問題交由 Bedrock 生成回覆  ← M8 生成式 AI</span></span></code></pre></div><blockquote><p>💡 現成 AI 服務、生成式 AI、資料分析，常常組合在一起解決一個真實業務問題——這正是 M8、M8b 兩章的整合概念。</p></blockquote><h2 id="考試重點整理" tabindex="-1">考試重點整理 <a class="header-anchor" href="#考試重點整理" aria-label="Permalink to &quot;考試重點整理&quot;">​</a></h2><ul><li><strong>資料管線五段</strong>：Kinesis（即時串流收集）→ S3 + Lake Formation（資料湖儲存）→ Glue（ETL＋資料目錄）→ Athena / Redshift / EMR（分析）→ QuickSight（視覺化）</li><li>🚨 <strong>高頻辨別</strong>：即時串流 → <strong>Kinesis</strong>；SQL 查 S3 無伺服器 → <strong>Athena</strong>；ETL → <strong>Glue</strong>；儀表板 → <strong>QuickSight</strong></li><li><strong>儲存要點</strong>：資料實際存在 <strong>S3</strong>；<strong>Lake Formation</strong> 是快速建置資料湖＋細緻權限治理的那一層（不是儲存本身）</li><li><strong>Glue Data Catalog</strong>：Glue 爬梳 S3、建立「資料目錄」，Athena / Redshift 才知道怎麼查 S3 的資料</li><li><strong>三種「分析」的差別</strong>：<strong>Athena</strong>（無伺服器、SQL 查 S3、臨時查詢）｜<strong>EMR</strong>（Hadoop/Spark、超大規模重運算）｜<strong>Redshift</strong>（資料倉儲、結構化資料的複雜 BI／OLAP）</li><li><strong>QuickSight</strong> = 無伺服器 BI，把分析結果變成互動式儀表板</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>即時串流資料收集（IoT、點擊流）</td><td><strong>Kinesis</strong></td></tr><tr><td>集中存放各種原始資料、建資料湖</td><td><strong>S3 + Lake Formation</strong></td></tr><tr><td>資料 ETL / 整理轉換</td><td><strong>Glue</strong></td></tr><tr><td>自動爬取 S3 結構、建立資料目錄</td><td><strong>Glue（Data Catalog）</strong></td></tr><tr><td>用 SQL 直接查 S3（無伺服器）</td><td><strong>Athena</strong></td></tr><tr><td>超大規模 Hadoop / Spark 大數據處理</td><td><strong>EMR</strong></td></tr><tr><td>對結構化資料跑複雜 BI 分析（OLAP）</td><td><strong>Redshift</strong></td></tr><tr><td>BI 儀表板與視覺化</td><td><strong>QuickSight</strong></td></tr></tbody></table>`,49)])])}const u=o(r,[["render",e]]);export{c as __pageData,u as default};
